div.script:
// Function to fetch products function fetchProducts(query)
                                   { let selectBox =
                                   document.getElementById("select_multi_product");
                                   selectBox.innerHTML = 'Loading...'; // Show
                                   loading //console.log("Sending query:", query); // Debug the
                                   search query fetch('/my/wo/search/stock_product', { method:
                                   "POST", headers: { "Content-Type": "application/json",
                                   "X-Requested-With": "XMLHttpRequest" }, body: JSON.stringify({
                                   query: query }) }) .then(response => response.json()) .then(data
                                   => { //console.log("Server response:", data); // Debug the
                                   server response if (!data.result || !Array.isArray(data.result))
                                   { console.error("Invalid response format:", data); return; } let
                                   stockProducts = data.result; // Clear existing select options
                                   selectBox.innerHTML = ''; // Find the ul element inside
                                   .ms-options let ulElement = document.querySelector('.ms-options
                                   ul'); if (!ulElement) { console.error("The ul element inside
                                   .ms-options was not found."); //return; } if (ulElement){
                                   ulElement.innerHTML = ''; } stockProducts.forEach(product => {
                                   let option = document.createElement("option"); option.value =
                                   product.id; option.textContent = product.name;
                                   selectBox.appendChild(option); if (ulElement){ let liElement =
                                   document.createElement("li");
                                   liElement.setAttribute('data-search-term',
                                   product.name.toLowerCase()); let labelElement =
                                   document.createElement("label");
                                   labelElement.setAttribute('for', `ms-opt-${product.id}`); let
                                   inputElement = document.createElement("input");
                                   inputElement.type = "checkbox"; inputElement.id =
                                   `ms-opt-${product.id}`; inputElement.value = product.id;
                                   inputElement.title = product.name; let textNode =
                                   document.createTextNode(product.name);
                                   labelElement.appendChild(inputElement);
                                   labelElement.appendChild(textNode);
                                   liElement.appendChild(labelElement);
                                   ulElement.appendChild(liElement); } }); // Refresh the
                                   multi-select library (if applicable)
                                   //$('#select_multi_product').multiSelect('refresh'); // Example
                                   for ms-options }) .catch(error => console.error("Error fetching
                                   products:", error)); } // Load initial products fetchProducts();
                                   // Use MutationObserver to detect when the search input is added
                                   to the DOM const observer = new MutationObserver((mutationsList,
                                   observer) => { const searchInput =
                                   document.querySelector('.ms-search input[type="text"]'); if
                                   (searchInput) { // Add the ID to the search input searchInput.id
                                   = "search_stock_product"; // Attach the keyup event listener for
                                   live search searchInput.addEventListener("keyup", function () {
                                   let query = this.value; //console.log("Search query:", query);
                                   // Debug the search query if (query.length < 2) return; //
                                   Prevent searching for short queries fetchProducts(query); }); //
                                   Stop observing once the search input is found
                                   observer.disconnect(); } }); // Start observing the document for
                                   changes observer.observe(document.body, { childList: true,
                                   subtree: true });
